import React from "react";

function Home(){
    const handleLogout =()=>{
        localStorage.clear()
        window.location.reload()
    }


    return(
        <div>
            <h1>This is a placeholder Homepage for Catsa!!!!</h1>
            <button onClick={handleLogout}>Logout</button>
        </div>
    );
}

export default Home;
